SELECT market_id, COUNT(vendor_id) AS number_of_vendors
FROM market_vendors
GROUP BY market_id;

SELECT COUNT(vendor_id) AS number_of_vendors
FROM market_vendors
WHERE market_id = 123;

SELECT COUNT(DISTINCT vendor_id) AS unique_vendor_count
FROM market_vendors
WHERE market_id = 1;

SELECT COUNT(DISTINCT mv.vendor_id) AS vendor_count
FROM market_vendors mv
WHERE mv.market_id = 1;
